import type { FacetMetadataSchema } from "@/lib/data-table/types";
import type { InferSchemaType, SchemaDefinition } from "@/lib/store/schema";

export interface GetDataOptions<T extends SchemaDefinition> {
  filters: Partial<InferSchemaType<T>>;
}

export interface GetDataResult<R = Record<string, unknown>> {
  rows: R[];
  total: number;
  facets?: Record<string, FacetMetadataSchema>;
}

export interface TableMCPConfig<
  T extends SchemaDefinition,
  R = Record<string, unknown>,
> {
  schema: T;
  getData: (options: GetDataOptions<T>) => Promise<GetDataResult<R>>;
  description: string;
  name?: string;
}

import type { SchemaDefinition } from "@/lib/store/schema";
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { WebStandardStreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/webStandardStreamableHttp.js";
import { z } from "zod";
import { deserializeFilters } from "./deserialize";
import { schemaToZod } from "./schema-to-zod";
import type { TableMCPConfig } from "./types";

function createServer<T extends SchemaDefinition, R = Record<string, unknown>>(
  config: TableMCPConfig<T, R>,
  filtersSchema: z.ZodObject<z.ZodRawShape>,
) {
  const server = new McpServer({
    name: config.name ?? "data-table",
    version: "1.0.0",
  });

  server.tool(
    "query_table",
    config.description,
    {
      filters: filtersSchema.optional(),
      format: z.enum(["json", "metadata"]).default("json"),
    },
    async ({ filters: rawFilters, format }) => {
      try {
        const filters = rawFilters
          ? deserializeFilters(config.schema, rawFilters)
          : {};

        const result = await config.getData({
          filters: filters as Parameters<typeof config.getData>[0]["filters"],
        });

        const output =
          format === "metadata"
            ? { total: result.total, facets: result.facets ?? {} }
            : { rows: result.rows, total: result.total };

        return {
          content: [{ type: "text" as const, text: JSON.stringify(output) }],
        };
      } catch (e) {
        return {
          content: [
            {
              type: "text" as const,
              text: `getData failed: ${e instanceof Error ? e.message : String(e)}`,
            },
          ],
          isError: true,
        };
      }
    },
  );

  return server;
}

export function createTableMCPHandler<
  T extends SchemaDefinition,
  R = Record<string, unknown>,
>(config: TableMCPConfig<T, R>) {
  const filtersSchema = schemaToZod(config.schema);

  return async function handler(request: Request): Promise<Response> {
    const server = createServer(config, filtersSchema);
    const transport = new WebStandardStreamableHTTPServerTransport({
      sessionIdGenerator: undefined,
      enableJsonResponse: true,
    });
    await server.connect(transport);
    try {
      return await transport.handleRequest(request);
    } finally {
      await server.close();
    }
  };
}

import type { FieldConfig, SchemaDefinition } from "@/lib/store/schema";
import { z, type ZodTypeAny } from "zod";

/**
 * Convert a single FieldConfig to its Zod equivalent.
 */
function fieldConfigToZod(config: FieldConfig<unknown>): ZodTypeAny {
  switch (config.type) {
    case "string":
      return z.string().optional();
    case "number":
      return z.number().optional();
    case "boolean":
      return z.boolean().optional();
    case "timestamp":
      return z.number().optional().describe("Unix ms");
    case "stringLiteral":
      if (config.literals && config.literals.length > 0) {
        return z
          .enum(config.literals as unknown as [string, ...string[]])
          .optional();
      }
      return z.string().optional();
    case "sort":
      return z.object({ id: z.string(), desc: z.boolean() }).optional();
    case "array": {
      const itemZod = config.itemConfig
        ? fieldConfigToZod(config.itemConfig)
        : z.unknown();
      // Remove .optional() from item schema inside arrays
      const unwrapped =
        itemZod instanceof z.ZodOptional ? itemZod.unwrap() : itemZod;
      return z.array(unwrapped).optional();
    }
    default:
      return z.unknown().optional();
  }
}

/**
 * Convert a SchemaDefinition to a Zod object schema for the `filters` parameter.
 * The SDK auto-converts Zod → JSON Schema for tools/list.
 */
export function schemaToZod(
  schema: SchemaDefinition,
): z.ZodObject<Record<string, ZodTypeAny>> {
  const shape: Record<string, ZodTypeAny> = {};
  for (const [key, fieldBuilder] of Object.entries(schema)) {
    shape[key] = fieldConfigToZod(fieldBuilder._config);
  }
  return z.object(shape);
}

import type { FieldConfig, SchemaDefinition } from "@/lib/store/schema";

/**
 * Deserialize raw MCP JSON values into typed values based on the schema.
 * Only timestamps need conversion (number → Date). All other types pass through.
 */
export function deserializeFilters(
  schema: SchemaDefinition,
  raw: Record<string, unknown>,
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(raw)) {
    if (value === undefined || value === null) continue;

    const fieldBuilder = schema[key];
    if (!fieldBuilder) continue;

    result[key] = deserializeValue(fieldBuilder._config, value);
  }

  return result;
}

function deserializeValue(
  config: FieldConfig<unknown>,
  value: unknown,
): unknown {
  if (config.type === "timestamp" && typeof value === "number") {
    return new Date(value);
  }

  if (config.type === "array" && Array.isArray(value) && config.itemConfig) {
    return value.map((item) => deserializeValue(config.itemConfig!, item));
  }

  return value;
}
